@import '../../utils/control-density.css';

:host {
  display: inline-flex;
  flex-shrink: 0;
  width: var(--ds-control-height);
  height: var(--ds-control-height);
}

:host(.avatar--md) {
  --_avatar-stroke: var(--dimension-stroke-width-015);
}

:host(.avatar--sm) {
  --_avatar-stroke: var(--dimension-stroke-width-012);
}

:host(.avatar--xs) {
  --_avatar-stroke: calc(var(--dimension-stroke-width-base) * 3 / 32);
}

.avatar {
  display: flex;
  align-items: center;
  justify-content: center;
  box-sizing: border-box;
  width: 100%;
  height: 100%;
  border-radius: var(--dimension-radius-half);
  box-shadow: inset 0 0 0 var(--_avatar-stroke) var(--color-foreground-quaternary);
}

import { Component, h, Host, Prop } from '@stencil/core';
import type { IconColor } from '../Icon/Icon';

export type AvatarSize = 'md' | 'sm' | 'xs';

@Component({
  tag: 'ds-avatar',
  styleUrl: 'Avatar.css',
  scoped: true,
})
export class Avatar {
  /** Canonical IcoMo icon name displayed inside the avatar. */
  @Prop() icon: string = '';

  /** Semantic icon hierarchy. Use primary for stronger emphasis; secondary is the default. */
  @Prop() iconColor: IconColor = 'secondary';

  /** Circle and icon density. Maps to 32/20, 24/16, or 16/12 px. */
  @Prop() size: AvatarSize = 'md';

  /** Optional accessible label. Omit when the surrounding content already conveys the meaning. */
  @Prop() label: string | undefined;

  render() {
    return (
      <Host class={{ [`ds-control--${this.size}`]: true, [`avatar--${this.size}`]: true }}>
        <span
          class="avatar"
          role={this.label ? 'img' : 'presentation'}
          aria-label={this.label}
          aria-hidden={!this.label ? 'true' : undefined}
        >
          <ds-icon name={this.icon} size={this.size} color={this.iconColor} />
        </span>
      </Host>
    );
  }
}
